Starter template for new scenes: `@tool
extends RefCounted

func run(ctx) -> void:
	var root: Node = ctx.get_scene_root()
	if root == null:
		var new_root: Node3D = Node3D.new()
		new_root.name = "GeneratedScene"
		ctx.set_scene_root(new_root)
		root = new_root
		ctx.log("Created scene root")

	var child: Node3D = Node3D.new()
	child.name = "GeneratedContent"
	root.add_child(child)
	ctx.own(child)
	ctx.mark_modified()`.

Starter template for instancing a subscene: `@tool
extends RefCounted

func run(ctx) -> void:
	var root: Node = ctx.get_scene_root()
	if root == null:
		ctx.error("Scene root was null")
		return
	var player: Node3D = ctx.instance_scene(root, "res://scenes/player/player.tscn", "Player") as Node3D
	if player == null:
		return
	player.position = Vector3(0.0, 0.0, 0.0)
	ctx.log("Instanced Player")`.

Starter template for targeted mutation: `@tool
extends RefCounted

func run(ctx) -> void:
	var root: Node = ctx.get_scene_root()
	if root == null:
		ctx.error("Scene root was null")
		return
	var root_class: String = root.get_class()
	var root_name: String = String(root.get_name())
	ctx.log("root_class=%s" % root_class)
	ctx.log("root_name=%s" % root_name)
	var panel: Variant = root.get("theme_override_styles/panel")
	ctx.log("panel_value=%s" % str(panel))
	if panel is StyleBoxFlat:
		var sb: StyleBoxFlat = panel as StyleBoxFlat
		ctx.log("before_bg=%s" % str(sb.bg_color))
		sb.bg_color = Color(1.0, 0.0, 0.85, 1.0)
		ctx.log("after_bg=%s" % str(sb.bg_color))
		ctx.mark_modified()`.
